fn supports_javascript(path: &str) -> bool {
    matches!(
        path.rsplit('.')
            .next()
            .unwrap_or("")
            .to_ascii_lowercase()
            .as_str(),
        "ts" | "tsx" | "js" | "jsx" | "mjs" | "cjs"
    )
}

fn split_on_comma(tokens: &[Token]) -> Vec<&[Token]> {
    let mut items = Vec::new();
    let mut start = 0;
    let mut angle_depth = 0usize;
    for (index, token) in tokens.iter().enumerate() {
        if token.is_punctuation('<') {
            angle_depth += 1;
        } else if token.is_punctuation('>') {
            angle_depth = angle_depth.saturating_sub(1);
        } else if angle_depth == 0 && token.is_punctuation(',') {
            items.push(&tokens[start..index]);
            start = index + 1;
        }
    }
    items.push(&tokens[start..]);
    items
}

fn next_non_newline(tokens: &[Token], start: usize) -> Option<usize> {
    (start..tokens.len()).find(|index| !tokens[*index].is_newline())
}
